import CoreGraphics
import SwiftUI

/// Parses the Subtract.svg path data once at launch and caches the result
/// as a CGPath.  The SVG viewBox is 872 × 885 (Y increases downward).
///
/// Handles M (moveto), L (lineto), C (cubic Bézier), and Z (closepath)
/// commands — the full command set used in Subtract.svg.
enum SVGTreeShadow {

    // MARK: - Cached path

    /// CGPath in SVG coordinate space (origin top-left, 872 × 885).
    /// Evaluated lazily on first access; safe to call from @MainActor.
    nonisolated(unsafe) static let cgPath: CGPath = buildPath(from: pathData)

    /// Convenience SwiftUI Path wrapping the cached CGPath.
    static let swiftUIPath = Path(cgPath)

    // MARK: - Parser

    private static func buildPath(from d: String) -> CGPath {
        let mutablePath = CGMutablePath()
        var nums:      [Double] = []
        var numBuf:    String   = ""
        var cmd:       Character = " "

        func flushNum() {
            guard !numBuf.isEmpty, let v = Double(numBuf) else { numBuf = ""; return }
            nums.append(v)
            numBuf = ""
        }

        func applyCmd() {
            switch cmd {
            case "M":
                guard nums.count >= 2 else { return }
                mutablePath.move(to: CGPoint(x: nums[0], y: nums[1]))
                nums.removeAll()
            case "L":
                while nums.count >= 2 {
                    mutablePath.addLine(to: CGPoint(x: nums[0], y: nums[1]))
                    nums.removeFirst(2)
                }
            case "C":
                while nums.count >= 6 {
                    mutablePath.addCurve(
                        to:       CGPoint(x: nums[4], y: nums[5]),
                        control1: CGPoint(x: nums[0], y: nums[1]),
                        control2: CGPoint(x: nums[2], y: nums[3])
                    )
                    nums.removeFirst(6)
                }
            case "Z":
                mutablePath.closeSubpath()
                nums.removeAll()
            default:
                break
            }
        }

        for ch in d {
            switch ch {
            case "M", "L", "C":
                flushNum()
                applyCmd()
                cmd = ch
                nums.removeAll()
            case "Z":
                flushNum()
                applyCmd()       // flush any lingering numbers
                cmd = "Z"
                applyCmd()       // close the subpath
            case "0"..."9", ".":
                numBuf.append(ch)
            case "-":
                flushNum()
                numBuf = "-"
            case " ", ",", "\n", "\r", "\t":
                flushNum()
            default:
                break
            }
        }
        flushNum()
        applyCmd()

        return mutablePath
    }

